Calculate_Batch_Size.inputs:
@add(
  div(
    length(body('Filter_Payload_by_Level')), 
    outputs('Calculate_Parallelism')
  ), 
  if(
    greaterOrEquals(
      mod(
        length(body('Filter_Payload_by_Level')),
        outputs('Calculate_Parallelism')
      ),
      1
    ), 
    1, 
    0
  )
)

